(window.webpackJsonp=window.webpackJsonp||[]).push([[17],{370:function(t,e){"use strict";e.__esModule=!0,e.default={render:function(){return this.$createElement("div",{staticClass:"theme-default-content content__default",domProps:{innerHTML:"<h2 id=\"graduate-studies\"><a href=\"#graduate-studies\" class=\"header-anchor\">#</a> Graduate Studies</h2> <p>VascMind Lab conducts research on cardio-cerebrovascular imaging analysis, ophthalmic medical imaging, medical foundation-model post-training, and medical agents. We focus on real clinical problems at the intersection of medicine and engineering, combining fundamental algorithm research with translational collaborations with clinical hospitals.</p> <h3 id=\"research-directions\"><a href=\"#research-directions\" class=\"header-anchor\">#</a> Research Directions</h3> <table><thead><tr><th>Direction</th> <th>Focus</th></tr></thead> <tbody><tr><td>Cardio-cerebrovascular imaging analysis</td> <td>Modeling vascular structure, function, and disease-related imaging biomarkers.</td></tr> <tr><td>Ophthalmic medical imaging</td> <td>Analysis and clinical applications based on fundus, OCT/OCTA, and related imaging modalities.</td></tr> <tr><td>Medical foundation-model post-training and agents</td> <td>Medical-domain post-training, multimodal reasoning, tool use, and medical agents for clinical scenarios.</td></tr></tbody></table> <h3 id=\"candidate-profile\"><a href=\"#candidate-profile\" class=\"header-anchor\">#</a> Candidate Profile</h3> <ul><li>Applicants interested in master's, regular PhD, or direct PhD programs at Nanjing University; 2027 undergraduate students with expected recommendation-based admission eligibility are encouraged to contact us early.</li> <li>Clear interest in medical imaging, medical foundation models, or medicine-engineering interdisciplinary research, with strong coding ability.</li> <li>Reliable, willing to commit to long-term research, and proactive in communication when facing problems.</li> <li>Publication experience or open-source community contributions are a plus.</li></ul> <h3 id=\"admissions\"><a href=\"#admissions\" class=\"header-anchor\">#</a> Admissions</h3> <table><tbody><tr><th>Affiliation</th> <td>School of Biomedical Engineering, Nanjing University (Suzhou Campus)</td></tr> <tr><th>Admissions Advisor</th> <td>Prof. Jiong Zhang, new PI</td></tr> <tr><th>Program Types</th> <td>Master's, regular PhD, and direct PhD students are all welcome.</td></tr> <tr><th>Positions</th> <td>Specific openings are subject to the annual admissions plans of Nanjing University and the school.</td></tr> <tr><th>Application Notes</th> <td>Direct PhD applicants should attend the summer camp for Computer Application Technology under the School of Modern Engineering and Applied Sciences (034). Master's and regular PhD applicants should follow the annual admissions notices from Nanjing University and the school.</td></tr> <tr><th>Advisor Homepage</th> <td><a href=\"https://jiongzhang-john.github.io\" target=\"_blank\" rel=\"noopener noreferrer\">https://jiongzhang-john.github.io</a></td></tr></tbody></table>"}})}}}}]);